prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskMid ?midName ?taskBefore ?beforeName ?taskAfter ?afterName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "f404135647444aedabe98bb54c000517" .
  ?model tai:belongsTo ?org .

  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?model .

  ?before bbo:name ?beforeName .
  FILTER(CONTAINS(LCASE(STR(?beforeName)), LCASE("CancellationA cknowledge")))

  ?after bbo:name ?afterName .
  FILTER(CONTAINS(LCASE(STR(?afterName)), LCASE("Notification")))

  ?beforeEdge a bbo:SequenceFlow ;
              bbo:has_sourceRef ?before ;
              bbo:has_targetRef ?taskMid .

  ?midEdge a bbo:SequenceFlow ;
            bbo:has_sourceRef ?taskMid ;
            bbo:has_targetRef ?after .

  ?taskMid a bboExt:ChoreographyTask .
  OPTIONAL { ?taskMid bbo:name ?midName . }

  FILTER(?before != ?taskMid && ?after != ?taskMid)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelIdType ?modelId ?modelName ?created WHERE {
  {
    ?model a bboExt:Model ; tai:normalizedId "f404135647444aedabe98bb54c000517" .
    BIND("normalizedId" AS ?modelIdType)
    OPTIONAL { ?model bbo:name ?modelName . }
    OPTIONAL { ?model tai:modelCreated ?created . }
    BIND("f404135647444aedabe98bb54c000517" AS ?modelId)
  }
  UNION
  {
    ?model a bboExt:Model ; tai:originalId "f404135647444aedabe98bb54c000517" .
    BIND("originalId" AS ?modelIdType)
    OPTIONAL { ?model bbo:name ?modelName . }
    OPTIONAL { ?model tai:modelCreated ?created . }
    BIND("f404135647444aedabe98bb54c000517" AS ?modelId)
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?name ?type WHERE {
  ?model a bboExt:Model ;
         tai:originalId "f404135647444aedabe98bb54c000517" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?model .

  ?elem bbo:name ?name ;
        a ?type .

  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("cancellation")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("notification"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskMid ?taskMidName ?before ?beforeName ?after ?afterName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "f404135647444aedabe98bb54c000517" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?model .

  ?beforeEdge a bbo:SequenceFlow ;
              bbo:has_sourceRef ?before ;
              bbo:has_targetRef ?taskMid .

  ?midEdge a bbo:SequenceFlow ;
            bbo:has_sourceRef ?taskMid ;
            bbo:has_targetRef ?after .

  ?taskMid a bboExt:ChoreographyTask .

  OPTIONAL { ?taskMid bbo:name ?taskMidName . }
  OPTIONAL { ?before bbo:name ?beforeName . }
  OPTIONAL { ?after bbo:name ?afterName . }

  FILTER(
    (BOUND(?beforeName) && (CONTAINS(LCASE(STR(?beforeName)), LCASE("cancellation")) || CONTAINS(LCASE(STR(?beforeName)), LCASE("cancel"))))
    ||
    (BOUND(?afterName) && (CONTAINS(LCASE(STR(?afterName)), LCASE("notification")) || CONTAINS(LCASE(STR(?afterName)), LCASE("notify"))))
  )
}
LIMIT 25
